ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?opening_year WHERE {
  ?hotels a :Hotels .
  ?rooms a :Rooms .
  ?rooms p:hasHotels ?hotels .
  ?hotels p:Opening_Year ?opening_year .
  ?rooms p:Rate ?rate_o .
}
ORDER BY DESC(?rate_o)
LIMIT 1 }
  full: { SELECT ?opening_year ?opening_month WHERE {
  ?hotels a :Hotels .
  ?rooms a :Rooms .
  ?rooms p:hasHotels ?hotels .
  ?hotels p:Opening_Year ?opening_year .
  ?hotels p:Opening_Month ?opening_month .
  ?rooms p:Rate ?rate_o .
}
ORDER BY DESC(?rate_o)
LIMIT 1 }
  component_2: { SELECT ?opening_month WHERE {
  ?hotels a :Hotels .
  ?rooms a :Rooms .
  ?rooms p:hasHotels ?hotels .
  ?hotels p:Opening_Month ?opening_month .
  ?rooms p:Rate ?rate_o .
}
ORDER BY DESC(?rate_o)
LIMIT 1 }
}

PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?opening_year ?opening_month WHERE {
  ?hotels a :Hotels .
  ?rooms a :Rooms .
  ?rooms p:hasHotels ?hotels .
  ?hotels p:Opening_Year ?opening_year .
  ?hotels p:Opening_Month ?opening_month .
  ?rooms p:Type ?type_f .
  FILTER(STR(?type_f) = "Sea View")
} }
  component: { SELECT ?opening_month WHERE {
  ?hotels a :Hotels .
  ?rooms a :Rooms .
  ?rooms p:hasHotels ?hotels .
  ?hotels p:Opening_Month ?opening_month .
  ?rooms p:Type ?type_f .
  FILTER(STR(?type_f) = "Sea View")
} }
  component_2: { SELECT ?opening_year WHERE {
  ?hotels a :Hotels .
  ?rooms a :Rooms .
  ?rooms p:hasHotels ?hotels .
  ?hotels p:Opening_Year ?opening_year .
  ?rooms p:Type ?type_f .
  FILTER(STR(?type_f) = "Sea View")
} }
}
